const response = $input.first().json;
const reactions = response.result || response;

if (!Array.isArray(reactions) || reactions.length === 0) {
  return [{ json: { linkedin_url: '', name: 'No reactions found', job_info: '' } }];
}

// Extract LinkedIn URL from each reactor
return reactions
  .filter(r => r.link && r.link.includes('linkedin.com/in/'))
  .map(r => {
    const parts = (r.title || '').split(' - ');
    return {
      json: {
        linkedin_url: r.link  || '',
        name:         (parts[0] || '').trim(),
        job_info:     parts.slice(1).join(' - ').trim()
      }
    };
  });

const response     = $input.first().json;
const data         = response.result || response;
const reactor      = $('Parse Reaction List').first().json;

const currentYear  = new Date().getFullYear();
const firstYear    = parseInt(data.firstRoleYear || data.first_role_year || 0);

return [{ json: {
  reaction_name:     reactor.name         || '',
  reaction_job_info: reactor.job_info     || '',
  name:              data.name            || reactor.name || '',
  job_title:         data.jobTitle        || data.job_title || '',
  company:           data.company         || '',
  headline:          data.headline        || '',
  location:          data.location        || '',
  country:           data.country         || '',
  industry:          data.industry        || '',
  email:             data.email           || '',
  mobile:            data.mobileNumber    || data.mobile  || '',
  connections:       data.connections     || '',
  is_employed:       data.isCurrentlyEmployed !== undefined ? String(data.isCurrentlyEmployed) : '',
  years_experience:  firstYear ? String(currentYear - firstYear) : '',
  linkedin_url:      data.linkedinUrl     || data.linkedin_url || reactor.linkedin_url
}}];
